import requests

def fetch_and_display_url_content(url: str):
    """
    Fetches the content from the given URL and prints it.
    Handles various network and HTTP errors gracefully.

    Args:
        url (str): The URL to fetch content from.
    """
    try:
        # Set a reasonable timeout to prevent hanging requests indefinitely
        # A 10-second timeout is often a good starting point for web requests
        response = requests.get(url, timeout=10)

        # Raise an HTTPError for bad responses (4xx or 5xx)
        response.raise_for_status()

        print(f"Successfully fetched content from {url}:")
        print("-" * 80)
        print(response.text)
        print("-" * 80)

    except requests.exceptions.Timeout:
        print(f"Error fetching {url}: The request timed out after 10 seconds.")
    except requests.exceptions.ConnectionError as e:
        print(f"Error fetching {url}: Could not connect to the server. Please check the URL or your network connection. Details: {e}")
    except requests.exceptions.HTTPError as e:
        print(f"Error fetching {url}: HTTP Error {e.response.status_code} - {e.response.reason}. Details: {e}")
    except requests.exceptions.RequestException as e:
        print(f"An unexpected error occurred while making the request to {url}: {e}")
    except ValueError:
        print(f"Error: Invalid URL format provided: {url}")
    except Exception as e:
        print(f"A general unexpected error occurred: {e}")